import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)

def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

bm, am = pkg_map(b), pkg_map(a)
if bm == am:
    print('All package versions match baseline.')
else:
    for k in sorted(set(list(bm.keys()) + list(am.keys()))):
        bv, av = bm.get(k, 'MISSING'), am.get(k, 'MISSING')
        if bv != av:
            print(f'DIFF: {k[0]} {k[1]}: {bv} -> {av}')
"

